Step 2: Implement the AI Client (BYOK Logic)
Create packages/common/ai-client/src/llm-service.ts. This uses the Factory Pattern to switch between Ollama, OpenAI, and others.
code
TypeScript
// packages/common/ai-client/src/types.ts
export type AIProvider = 'openai' | 'anthropic' | 'ollama' | 'custom';

export interface AIConfig {
  provider: AIProvider;
  apiKey?: string; // Optional for Ollama
  baseUrl?: string; // Essential for Ollama (e.g., http://localhost:11434)
  modelName: string; // e.g., 'gpt-4', 'llama3'
}

export interface ChatMessage {
  role: 'user' | 'system' | 'assistant';
  content: string;
}

// packages/common/ai-client/src/service.ts
import { createOpenAI } from '@ai-sdk/openai';
import { createOllama } from 'ollama-ai-provider'; // Conceptual wrapper or direct fetch
import { streamText } from 'ai';

export class LLMService {
  private config: AIConfig;

  constructor(config: AIConfig) {
    this.config = config;
  }

  private getModel() {
    switch (this.config.provider) {
      case 'openai':
        const openai = createOpenAI({ apiKey: this.config.apiKey });
        return openai(this.config.modelName);

      case 'ollama':
        // Using Vercel AI SDK standard interface for Ollama
        // If not using a library, we would use fetch() here directly
        const ollama = createOllama({ baseURL: this.config.baseUrl || 'http://localhost:11434/api' });
        return ollama(this.config.modelName);

      default:
        throw new Error('Provider not supported');
    }
  }

  async streamResponse(messages: ChatMessage[]) {
    const model = this.getModel();

    try {
      const result = await streamText({
        model,
        messages,
      });
      return result.toDataStreamResponse();
    } catch (error) {
      console.error("AI Service Error:", error);
      throw error;
    }
  }

  // Helper to check Ollama connectivity
  async checkLocalStatus(): Promise<boolean> {
    if (this.config.provider !== 'ollama') return true;
    try {
      const res = await fetch(`${this.config.baseUrl || 'http://localhost:11434'}/api/tags`);
      return res.ok;
    } catch (e) {
      return false;
    }
  }
}
Step 3: React Store for Settings (Jotai)
In packages/frontend/core/src/store/ai-settings.ts, we create the state to hold user keys and preferences.
code
TypeScript
import { atomWithStorage } from 'jotai/utils';
import { AIConfig } from '@affine/common/ai-client/types';

const DEFAULT_AI_CONFIG: AIConfig = {
  provider: 'ollama', // Default to privacy-first
  baseUrl: 'http://localhost:11434',
  modelName: 'llama3',
  apiKey: '',
};

// Persist to localStorage for now (Web). 
// In Electron, we would sync this with SafeStorage.
export const aiConfigAtom = atomWithStorage<AIConfig>('affine-ai-config', DEFAULT_AI_CONFIG);

export const isAiSettingsOpenAtom = atomWithStorage('affine-ai-modal-open', false);
Step 4: The AI Settings Modal UI
In packages/frontend/core/src/components/AISettingsModal.tsx:
code
Tsx
import React, { useState, useEffect } from 'react';
import { useAtom } from 'jotai';
import { aiConfigAtom, isAiSettingsOpenAtom } from '../store/ai-settings';

export const AISettingsModal = () => {
  const [isOpen, setIsOpen] = useAtom(isAiSettingsOpenAtom);
  const [config, setConfig] = useAtom(aiConfigAtom);
  const [ollamaModels, setOllamaModels] = useState<string[]>([]);

  // Fetch available Ollama models when provider is Ollama
  useEffect(() => {
    if (config.provider === 'ollama') {
      fetch(`${config.baseUrl}/api/tags`)
        .then(res => res.json())
        .then(data => setOllamaModels(data.models.map((m: any) => m.name)))
        .catch(() => console.warn('Could not fetch Ollama models'));
    }
  }, [config.provider, config.baseUrl]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
      <div className="bg-white dark:bg-gray-800 p-6 rounded-lg w-96 shadow-xl">
        <h2 className="text-xl font-bold mb-4 text-gray-900 dark:text-white">AI Configuration</h2>

        {/* Provider Selection */}
        <div className="mb-4">
          <label className="block text-sm font-medium mb-1">Provider</label>
          <select 
            className="w-full p-2 border rounded dark:bg-gray-700"
            value={config.provider}
            onChange={(e) => setConfig({ ...config, provider: e.target.value as any })}
          >
            <option value="ollama">Local (Ollama)</option>
            <option value="openai">OpenAI</option>
            <option value="anthropic">Anthropic</option>
          </select>
        </div>

        {/* Dynamic Fields */}
        {config.provider === 'ollama' ? (
          <>
            <div className="mb-4">
              <label className="block text-sm font-medium mb-1">Base URL</label>
              <input 
                type="text" 
                className="w-full p-2 border rounded dark:bg-gray-700"
                value={config.baseUrl}
                onChange={(e) => setConfig({ ...config, baseUrl: e.target.value })}
              />
            </div>
            <div className="mb-4">
              <label className="block text-sm font-medium mb-1">Model</label>
              <select 
                className="w-full p-2 border rounded dark:bg-gray-700"
                value={config.modelName}
                onChange={(e) => setConfig({ ...config, modelName: e.target.value })}
              >
                {ollamaModels.length > 0 ? (
                  ollamaModels.map(m => <option key={m} value={m}>{m}</option>)
                ) : (
                  <option value="llama3">llama3</option>
                )}
              </select>
            </div>
          </>
        ) : (
          <div className="mb-4">
            <label className="block text-sm font-medium mb-1">API Key</label>
            <input 
              type="password" 
              className="w-full p-2 border rounded dark:bg-gray-700"
              value={config.apiKey}
              onChange={(e) => setConfig({ ...config, apiKey: e.target.value })}
              placeholder="sk-..."
            />
          </div>
        )}

        <div className="flex justify-end gap-2 mt-6">
          <button onClick={() => setIsOpen(false)} className="px-4 py-2 text-gray-600">Cancel</button>
          <button onClick={() => setIsOpen(false)} className="px-4 py-2 bg-purple-600 text-white rounded">Save</button>
        </div>
      </div>
    </div>
  );
};
Step 5: Integration with Blocksuite Editor
Finally, we hook the LLMService into the editor UI. When a user highlights text and clicks "Summarize" or "Ask AI".
code
TypeScript
// packages/frontend/core/src/hooks/useAI.ts
import { useAtomValue } from 'jotai';
import { aiConfigAtom } from '../store/ai-settings';
import { LLMService } from '@affine/common/ai-client/service';
import { useCompletion } from 'ai/react'; // Vercel AI Hook

export const useAIAssistant = () => {
  const config = useAtomValue(aiConfigAtom);

  // Initialize Service
  const llmService = new LLMService(config);

  // Use Vercel AI SDK hook for streaming UI state management
  const { completion, complete, isLoading } = useCompletion({
    api: '/api/ai-proxy', // Only needed if proxying, but we are doing client-side usually for Electron
    // Custom fetch implementation to bypass Next.js API routes if purely client-side/electron
    fetch: async (url, options) => {
       // Here we invoke the LLMService directly instead of calling a fetch endpoint
       // This simulates the API call for local-first architecture
       const response = await llmService.streamResponse([
         { role: 'user', content: JSON.parse(options.body).prompt }
       ]);
       return response;
    }
  });

  const summarizeSelection = async (text: string) => {
    await complete(`Summarize the following text concisely:\n\n${text}`);
  };

  return {
    response: completion,
    isLoading,
    summarizeSelection
  };
};
Step 6: Docker/Run Configuration
To ensure the "Next App" runs easily with Ollama:
User Prerequisite: Install Ollama (curl -fsSL https://ollama.com/install.sh).
Run Command: ollama run llama3 (or model of choice).
CORS Issue: By default, Ollama blocks web requests. The user needs to set environment variables.
Linux/Mac: OLLAMA_ORIGINS="*" ollama serve
Windows: Set env var OLLAMA_ORIGINS to *.
Add a scripts/start-dev.sh:
code
Bash
#!/bin/bash
echo "Starting AFFiNE.Pro Dev Environment..."

# Check for Ollama
if ! command -v ollama &> /dev/null
then
    echo "WARN: Ollama could not be found. AI features will require an OpenAI key."
else
    echo "INFO: Ollama detected. Ensure you run 'ollama serve' with OLLAMA_ORIGINS='*'"
fi

# Start App
yarn workspace @affine/frontend-core dev
Summary of Deliverables
Tech Stack: Updated to include Vercel AI SDK (or generic adapters) + Jotai for config.
Privacy: "Local First" now extends to AI. Default is Ollama/Localhost.
Flexibility: Factory pattern allows swapping providers (BYOK).
UX: Settings modal provided to manage keys and models dynamically.
